extension FfiError: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeFfiError: FfiConverterRustBuffer {
    typealias SwiftType = FfiError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> FfiError {
        let variant: Int32 = try readInt(&buf)
        switch variant {




        case 1: return .InvalidAddress(
            try FfiConverterString.read(from: &buf)
            )
        case 2: return .InvalidField(
            try FfiConverterString.read(from: &buf)
            )
        case 3: return .InvalidHash(
            try FfiConverterString.read(from: &buf)
            )
        case 4: return .InvalidProofShape(
            try FfiConverterString.read(from: &buf)
            )
        case 5: return .InvalidArtifactKind(
            try FfiConverterString.read(from: &buf)
            )
        case 6: return .InvalidCompatibilityMode(
            try FfiConverterString.read(from: &buf)
            )
        case 7: return .InvalidExecutionPolicyMode(
            try FfiConverterString.read(from: &buf)
            )
        case 8: return .SessionNotFound(
            try FfiConverterString.read(from: &buf)
            )
        case 9: return .SignerNotFound(
            try FfiConverterString.read(from: &buf)
            )
        case 10: return .JobNotFound(
            try FfiConverterString.read(from: &buf)
            )
        case 11: return .SignerRequiresExternalSigning(
            try FfiConverterString.read(from: &buf)
            )
        case 12: return .InvalidManifest(
            try FfiConverterString.read(from: &buf)
            )
        case 13: return .OperationFailed(
            try FfiConverterString.read(from: &buf)
            )

         default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: FfiError, into buf: inout [UInt8]) {
        switch value {





        case let .InvalidAddress(v1):
            writeInt(&buf, Int32(1))
            FfiConverterString.write(v1, into: &buf)


        case let .InvalidField(v1):
            writeInt(&buf, Int32(2))
            FfiConverterString.write(v1, into: &buf)


        case let .InvalidHash(v1):
            writeInt(&buf, Int32(3))
            FfiConverterString.write(v1, into: &buf)


        case let .InvalidProofShape(v1):
            writeInt(&buf, Int32(4))
            FfiConverterString.write(v1, into: &buf)


        case let .InvalidArtifactKind(v1):
            writeInt(&buf, Int32(5))
            FfiConverterString.write(v1, into: &buf)


        case let .InvalidCompatibilityMode(v1):
            writeInt(&buf, Int32(6))
            FfiConverterString.write(v1, into: &buf)


        case let .InvalidExecutionPolicyMode(v1):
            writeInt(&buf, Int32(7))
            FfiConverterString.write(v1, into: &buf)


        case let .SessionNotFound(v1):
            writeInt(&buf, Int32(8))
            FfiConverterString.write(v1, into: &buf)


        case let .SignerNotFound(v1):
            writeInt(&buf, Int32(9))
            FfiConverterString.write(v1, into: &buf)


        case let .JobNotFound(v1):
            writeInt(&buf, Int32(10))
            FfiConverterString.write(v1, into: &buf)


        case let .SignerRequiresExternalSigning(v1):
            writeInt(&buf, Int32(11))
            FfiConverterString.write(v1, into: &buf)


        case let .InvalidManifest(v1):
            writeInt(&buf, Int32(12))
            FfiConverterString.write(v1, into: &buf)


        case let .OperationFailed(v1):
            writeInt(&buf, Int32(13))
            FfiConverterString.write(v1, into: &buf)

        }
    }
